use tokio::sync::mpsc;
use std::time::Duration;

/// Event channel with backpressure handling.
pub struct EventChannel<T> {
    sender: mpsc::Sender<T>,
    receiver: mpsc::Receiver<T>,
    max_capacity: usize,
}

impl<T> EventChannel<T> {
    pub fn new(capacity: usize) -> Self {
        let (sender, receiver) = mpsc::channel(capacity);
        Self {
            sender,
            receiver,
            max_capacity: capacity,
        }
    }

    /// Send with backpressure - blocks if channel is full.
    pub async fn send_backpressure(&mut self, event: T) -> Result<(), T> {
        self.sender.send(event).await.map_err(|e| e.into_inner())
    }

    /// Send with timeout - returns error if channel full.
    pub async fn send_timeout(&mut self, event: T, timeout: Duration) -> Result<(), SendError<T> {
        tokio::time::timeout(timeout, self.sender.send(event))
            .await
            .map_err(|_| SendError::Timeout)?
            .map_err(|e| SendError::Sender(e.into_inner()))
    }

    /// Try send - returns immediately with error if full.
    pub fn try_send(&mut self, event: T) -> Result<(), TrySendError<T>> {
        self.sender.try_send(event).map_err(|e| match e {
            mpsc::error::TrySendError::Full(_) => TrySendError::Full(event),
            mpsc::error::TrySendError::Closed(_) => TrySendError::Closed(event),
        })
    }
}

#[derive(Debug)]
pub enum SendError<T> {
    Timeout,
    Sender(T),
}

#[derive(Debug)]
pub enum TrySendError<T> {
    Full(T),
    Closed(T),
}
